mapper.select:
SELECT m.*, p.provider_name, e.endpoint_name FROM llm_model m LEFT JOIN llm_provider p ON m.provider_id = p.id LEFT JOIN llm_endpoint e ON m.endpoint_id = e.id WHERE m.del_flag = 0 and p.del_flag = 0 and e.del_flag = 0
AND m.provider_id = #{bo.providerId}
AND m.endpoint_id = #{bo.endpointId}
AND m.model_name LIKE CONCAT('%', #{bo.modelName}, '%')
AND m.display_name LIKE CONCAT('%', #{bo.displayName}, '%')
AND m.context_window = #{bo.contextWindow}
AND m.status = #{bo.status}
AND p.provider_name LIKE CONCAT('%', #{bo.providerName}, '%')
AND e.endpoint_name LIKE CONCAT('%', #{bo.endpointName}, '%')
